    { x: 43, y: 7, w: 52, h: 62, r: 4.1, z: 3, clip: 'polygon(5% 5%, 98% 2%, 97% 95%, 1% 98%)' },
    { x: 20, y: 42, w: 64, h: 53, r: -1.5, z: 4, clip: 'polygon(3% 5%, 98% 8%, 96% 96%, 2% 93%)' }
